class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLen = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j <= s.length(); j++) {
                String substr = s.substring(i, j);
                int zeros = 0, ones = 0;
                boolean valid = true;
                for (char c : substr.toCharArray()) {
                    if (c == '0') {
                        zeros++;
                    } else {
                        ones++;
                        if (ones > zeros) {
                            valid = false;
                            break;
                        }
                    }
                }
                if (valid && zeros == ones) {
                    maxLen = Math.max(maxLen, j - i);
                }
            }
        }
        return maxLen;
    }
}
